from __future__ import annotations


def _attr(
    attribution_id: str,
    node_id: str,
    source_id: str,
    source_level: str,
    category: str,
    base_amount: float,
    contribution: float | None,
    method: str,
    artifact_id: str,
) -> dict[str, object]:
    return {
        "attribution_id": attribution_id,
        "node_id": node_id,
        "source_id": source_id,
        "source_level": source_level,
        "category": category,
        "base_amount": base_amount,
        "contribution": contribution,
        "residual": 0.0,
        "method": method,
        "artifact_id": artifact_id,
    }


